import{Toast,Modal,restUrl,postJson}from"jui";const{success:success,error:error}=Toast;import{t as ts}from"vanilla-signal-i18n";const langs={zh:{Login:"登录",username:"用户名",password:"密码",Cancel:"取消","Enter Username Please":"请输入用户名","Enter Password Please":"请输入密码","Username Required":"用户名不能为空","Password Required":"密码不能为空","Login Success":"登录成功"}},t=e=>ts(e,langs),api=e=>restUrl+"/api/v1"+e,loginModal=new Modal({text:{title:t("Login"),confirm:t("Login"),cancel:t("Cancel")},escClose:!0,fields:[{label:t("username"),type:"text",name:"username",id:"username",placeholder:t("Enter Username Please"),required:!0},{label:t("password"),type:"password",name:"password",id:"password",placeholder:t("Enter Password Please"),required:!0}],onSubmit:async e=>{if(e.username.trim())if(e.password.trim()){loginModal.state.loading=!0;try{const s=await postJson(api("/auth/login"),{username:e.username,password:e.password});s.success?(success(t("Login Success")),setTimeout(()=>{window.location.href="/"},1e3)):error(s.message),loginModal.state.loading=!1}catch(e){e(e.message||t("Login Failed")),loginModal.state.loading=!1}}else error(t("Password Required"));else error(t("Username Required"))}});document.body.addEventListener("click",e=>{e.target.closest('[data-action="login"]')&&loginModal.show()});